import { isNil } from 'lodash-es';

import { strategies } from './strategies.js';
import type { ColorRuleBuilder } from './types.js';
import type { ColorRuleProps, MatchValue } from '../types/color-rule.js';
import { buildValidator, VALUE_MATCHERS } from '../utils/validators.js';

type BuildColorRule = (config: ColorRuleProps[]) => ColorRuleBuilder;

export const buildColorRule: BuildColorRule =
  (config) => (series, strategy) => {
    const currentStrategy = strategies[strategy]();
    const colorRuleMap = new Map();
    const isValid = buildValidator(
      currentStrategy.matchers as typeof VALUE_MATCHERS,
    );

    config.forEach((rule) => {
      const colorPaletteIndex = currentStrategy.colorPaletteIndex();
      series.forEach((currentSeries) => {
        const subject = currentStrategy.getSubject(rule, currentSeries);

        if (
          !isNil(subject) &&
          isValid(subject as MatchValue, rule.comparator, rule.matchValue)
        ) {
          const colorFromRule = currentStrategy.getColorFromRule(
            rule,
            currentStrategy.getName(currentSeries),
            colorPaletteIndex.next().value,
          );
          colorFromRule && colorRuleMap.set(currentSeries, colorFromRule);
        }
      });
    });

    return {
      for: (series) => colorRuleMap.get(series),
    };
  };
